INSERT INTO cast (movie_id, person_id, name, character_name) VALUES
(#{movieId}, #{cast.id}, #{cast.name}, #{cast.character_name})
ON DUPLICATE KEY UPDATE name = VALUES(name), character_name = VALUES(character_name);

INSERT INTO crew (movie_id, person_id, name, job) VALUES
(#{movieId}, #{crew.id}, #{crew.name}, #{crew.job})
ON DUPLICATE KEY UPDATE name = VALUES(name), job = VALUES(job);
